#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long W, X, Y, Z;
        scanf("%lld %lld %lld %lld", &W, &X, &Y, &Z);
        long long total = W + Y * Z;
        if (total > X) printf("overflow\n");
        else if (total == X) printf("filled\n");
        else printf("unfilled\n");
    }
    return 0;
}

