#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        W = int(next(it)); X = int(next(it)); Y = int(next(it)); Z = int(next(it))
        total = W + Y * Z
        if total > X:
            out.append('overflow')
        elif total == X:
            out.append('filled')
        else:
            out.append('unfilled')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

